16	static njs_int_t
17	njs_external_add(njs_vm_t *vm, njs_arr_t *protos,
18	    const njs_external_t *external, njs_uint_t n)
19	{
20	    size_t                size;
21	    njs_int_t             ret;
22	    njs_value_t           prop_name;
23	    const u_char          *start;
24	    njs_flathsh_t         *hash;
25	    njs_function_t        *function;
26	    njs_object_prop_t     *prop;
27	    njs_exotic_slots_t    *slot, *next;
28	    njs_flathsh_query_t   fhq;
29	    const njs_external_t  *end;
30	
31	    slot = njs_arr_add(protos);
32	    njs_memzero(slot, sizeof(njs_exotic_slots_t));
33	
34	    hash = &slot->external_shared_hash;
35	    njs_flathsh_init(hash);
36	
37	    if (n == 0) {
38	        return NJS_OK;
39	    }
40	
41	    fhq.replace = 0;
42	    fhq.proto = &njs_object_hash_proto;
43	    fhq.pool = vm->mem_pool;
44	
45	    end = external + n;
46	
47	    while (external < end) {
48	
49	        if ((external->flags & NJS_EXTERN_TYPE_MASK) == NJS_EXTERN_SELF) {
50	            slot->writable = external->u.object.writable;
51	            slot->configurable = external->u.object.configurable;
52	            slot->enumerable = external->u.object.enumerable;
53	            slot->prop_handler = external->u.object.prop_handler;
54	            slot->magic32 = external->u.object.magic32;
55	            slot->keys = external->u.object.keys;
56	
57	            external++;
58	            continue;
59	        }
60	
61	        if (external->flags & NJS_EXTERN_SYMBOL) {
62	            fhq.key_hash = external->name.symbol;
63	
64	        } else {
65	            ret = njs_atom_string_create(vm, &prop_name,
66	                                         external->name.string.start,
67	                                         external->name.string.length);
68	            if (njs_slow_path(ret != NJS_OK)) {
69	                return NJS_ERROR;
70	            }
71	
72	            fhq.key_hash = prop_name.atom_id;
73	        }
74	
75	        ret = njs_flathsh_unique_insert(hash, &fhq);
76	        if (njs_slow_path(ret != NJS_OK)) {
77	            njs_internal_error(vm, "flathsh insert failed");
78	            return NJS_ERROR;
79	        }
80	
81	        prop = fhq.value;
82	
83	        prop->type = NJS_PROPERTY;
84	        prop->enumerable = external->enumerable;
85	        prop->configurable = external->configurable;
86	        prop->writable = external->writable;
87	        prop->u.value = njs_value_invalid;
88	
89	
90	        switch (external->flags & NJS_EXTERN_TYPE_MASK) {
91	        case NJS_EXTERN_METHOD:
92	            function = njs_mp_zalloc(vm->mem_pool, sizeof(njs_function_t));
93	            if (njs_slow_path(function == NULL)) {
94	                goto memory_error;
95	            }
96	
97	            function->object.shared_hash = vm->shared->arrow_instance_hash;
98	            function->object.type = NJS_FUNCTION;
99	            function->object.shared = 1;
100	            function->object.extensible = 1;
101	            function->native = 1;
102	            function->u.native = external->u.method.native;
103	            function->magic8 = external->u.method.magic8;
104	            function->ctor = external->u.method.ctor;
105	
106	            njs_set_function(njs_prop_value(prop), function);
107	
108	            break;
109	
110	        case NJS_EXTERN_PROPERTY:
111	            if (external->u.property.handler != NULL) {
112	                prop->type = NJS_PROPERTY_HANDLER;
113	                prop->u.value.type = NJS_INVALID;
114	                prop->u.value.data.truth = 1;
115	                njs_prop_magic16(prop) = external->u.property.magic16;
116	                njs_prop_magic32(prop) = external->u.property.magic32;
117	                njs_prop_handler(prop) = external->u.property.handler;
118	
119	            } else {
120	                start = (u_char *) external->u.property.value;
121	                size = njs_strlen(start);
122	
123	                ret = njs_string_create(vm, &prop->u.value, start, size);
124	                if (njs_slow_path(ret != NJS_OK)) {
125	                    return NJS_ERROR;
126	                }
127	            }
128	
129	            break;
130	
131	        case NJS_EXTERN_OBJECT:
132	        default:
133	            next = njs_arr_item(protos, protos->items);
134	
135	            ret = njs_external_add(vm, protos, external->u.object.properties,
136	                                   external->u.object.nproperties);
137	            if (njs_slow_path(ret != NJS_OK)) {
138	                return ret;
139	            }
140	
141	            prop->type = NJS_PROPERTY_HANDLER;
142	            prop->u.value.type = NJS_INVALID;
143	            prop->u.value.data.truth = 1;
144	            njs_prop_magic16(prop) = next - slot;
145	            njs_prop_magic32(prop) = fhq.key_hash;
146	            njs_prop_handler(prop) = njs_external_prop_handler;
147	
148	            if (external->u.object.prop_handler) {
149	                if (next->prop_handler) {
150	                    njs_internal_error(vm, "overwritten self prop_handler");
151	                    return NJS_ERROR;
152	                }
153	
154	                next->writable = external->u.object.writable;
155	                next->configurable = external->u.object.configurable;
156	                next->enumerable = external->u.object.enumerable;
157	
158	                next->prop_handler = external->u.object.prop_handler;
159	                next->magic32 = external->u.object.magic32;
160	            }
161	
162	            if (external->u.object.keys) {
163	                if (next->keys) {
164	                    njs_internal_error(vm, "overwritten self keys");
165	                    return NJS_ERROR;
166	                }
167	
168	                next->keys = external->u.object.keys;
169	            }
170	
171	            break;
172	        }
173	
174	        external++;
175	    }
176	
177	    return NJS_OK;
178	
179	memory_error:
180	
181	    njs_memory_error(vm);
182	
183	    return NJS_ERROR;
184	}
