187	static njs_int_t
188	njs_external_prop_handler(njs_vm_t *vm, njs_object_prop_t *self,
189	    uint32_t atom_id, njs_value_t *value, njs_value_t *setval,
190	    njs_value_t *retval)
191	{
192	    njs_int_t            ret;
193	    njs_object_prop_t    *prop;
194	    njs_external_ptr_t   external;
195	    njs_object_value_t   *ov;
196	    njs_exotic_slots_t   *slots;
197	    njs_flathsh_query_t  fhq;
198	
199	    if (njs_slow_path(retval == NULL)) {
200	        return NJS_DECLINED;
201	    }
202	
203	    slots = NULL;
204	
205	    if (njs_slow_path(setval != NULL)) {
206	        *retval = *setval;
207	
208	    } else {
209	        ov = njs_object_value_alloc(vm, NJS_OBJ_TYPE_OBJECT, 0, NULL);
210	        if (njs_slow_path(ov == NULL)) {
211	            return NJS_ERROR;
212	        }
213	
214	        slots = njs_object(value)->slots + njs_prop_magic16(self);
215	
216	        ov->object.shared_hash = slots->external_shared_hash;
217	        ov->object.slots = slots;
218	
219	        external = njs_vm_external(vm, NJS_PROTO_ID_ANY, value);
220	
221	        njs_set_data(&ov->value, external, njs_value_external_tag(value));
222	        njs_set_object_value(retval, ov);
223	    }
224	
225	    fhq.key_hash = atom_id;
226	    fhq.replace = 1;
227	    fhq.pool = vm->mem_pool;
228	    fhq.proto = &njs_object_hash_proto;
229	
230	    ret = njs_flathsh_unique_insert(njs_object_hash(value), &fhq);
231	    if (njs_slow_path(ret != NJS_OK)) {
232	        njs_internal_error(vm, "flathsh insert/replace failed");
233	        return NJS_ERROR;
234	    }
235	
236	    prop = fhq.value;
237	
238	    prop->type = NJS_PROPERTY;
239	    prop->enumerable = self->enumerable;
240	    prop->configurable = self->configurable;
241	    prop->writable = self->writable;
242	
243	    prop->u.value = *retval;
244	
245	    return NJS_OK;
246	}
