249	static njs_uint_t
250	njs_external_protos(const njs_external_t *external, njs_uint_t size)
251	{
252	    njs_uint_t  n;
253	
254	    n = 1;
255	
256	    while (size != 0) {
257	        if ((external->flags & 3) == NJS_EXTERN_OBJECT) {
258	            n += njs_external_protos(external->u.object.properties,
259	                                     external->u.object.nproperties);
260	        }
261	
262	        size--;
263	        external++;
264	    }
265	
266	    return n;
267	}
