270	njs_int_t
271	njs_vm_external_prototype(njs_vm_t *vm, const njs_external_t *definition,
272	    njs_uint_t n)
273	{
274	    njs_arr_t   *protos, **pr;
275	    njs_int_t   ret;
276	    njs_uint_t  size;
277	
278	    size = njs_external_protos(definition, n) + 1;
279	
280	    protos = njs_arr_create(vm->mem_pool, size, sizeof(njs_exotic_slots_t));
281	    if (njs_slow_path(protos == NULL)) {
282	        njs_memory_error(vm);
283	        return -1;
284	    }
285	
286	    ret = njs_external_add(vm, protos, definition, n);
287	    if (njs_slow_path(ret != NJS_OK)) {
288	        njs_internal_error(vm, "njs_vm_external_add() failed");
289	        return -1;
290	    }
291	
292	    if (vm->protos == NULL) {
293	        vm->protos = njs_arr_create(vm->mem_pool, 4, sizeof(njs_arr_t *));
294	        if (njs_slow_path(vm->protos == NULL)) {
295	            return -1;
296	        }
297	    }
298	
299	    pr = njs_arr_add(vm->protos);
300	    if (njs_slow_path(pr == NULL)) {
301	        return -1;
302	    }
303	
304	    *pr = protos;
305	
306	    return vm->protos->items - 1;
307	}
