310	static njs_int_t
311	njs_vm_external_constructor_handler(njs_vm_t *vm, njs_object_prop_t *prop,
312	    uint32_t atom_id, njs_value_t *value, njs_value_t *setval,
313	    njs_value_t *retval)
314	{
315	    njs_set_function(retval, &njs_vm_ctor(vm, njs_prop_magic32(prop)));
316	
317	    return NJS_OK;
318	}
319	
320	
321	njs_int_t
322	njs_vm_external_constructor(njs_vm_t *vm, const njs_str_t *name,
323	    const njs_function_native_t native, const njs_external_t *ctor_props,
324	    njs_uint_t ctor_nprops, const njs_external_t *proto_props,
325	    njs_uint_t proto_nprops)
326	{
327	    njs_int_t               ret, index, proto_id;
328	    njs_arr_t               **pprotos;
329	    njs_function_t          *constructor;
330	    njs_exotic_slots_t      *slots;
331	    njs_object_prototype_t  *prototype;
332	
333	    index = njs_vm_ctor_push(vm);
334	    if (njs_slow_path(index < 0)) {
335	        njs_internal_error(vm, "njs_vm_ctor_push() failed");
336	        return -1;
337	    }
338	
339	    proto_id = njs_vm_external_prototype(vm, proto_props, proto_nprops);
340	    if (njs_slow_path(proto_id < 0)) {
341	        njs_internal_error(vm, "njs_vm_external_prototype(proto_props) failed");
342	        return -1;
343	    }
344	
345	    prototype = njs_shared_prototype(vm->shared, index);
346	    njs_memzero(prototype, sizeof(njs_object_prototype_t));
347	    prototype->object.type = NJS_OBJECT;
348	    prototype->object.extensible = 1;
349	
350	    pprotos = njs_arr_item(vm->protos, proto_id);
351	    slots = (*pprotos)->start;
352	    prototype->object.shared_hash = slots->external_shared_hash;
353	
354	    proto_id = njs_vm_external_prototype(vm, ctor_props, ctor_nprops);
355	    if (njs_slow_path(proto_id < 0)) {
356	        njs_internal_error(vm, "njs_vm_external_prototype(ctor_props) failed");
357	        return -1;
358	    }
359	
360	    constructor = njs_shared_ctor(vm->shared, index);
361	    njs_memzero(constructor, sizeof(njs_function_t));
362	    constructor->object.type = NJS_FUNCTION;
363	    constructor->u.native = native;
364	    constructor->magic8 = index;
365	    constructor->native = 1;
366	    constructor->ctor = 1;
367	
368	    pprotos = njs_arr_item(vm->protos, proto_id);
369	    slots = (*pprotos)->start;
370	    constructor->object.shared_hash = slots->external_shared_hash;
371	
372	    ret = njs_vm_bind_handler(vm, name, njs_vm_external_constructor_handler, 0,
373	                              index, 1);
374	    if (njs_slow_path(ret != NJS_OK)) {
375	        return NJS_ERROR;
376	    }
377	
378	    return index;
379	}
380	
381	
382	njs_int_t
383	njs_vm_external_create(njs_vm_t *vm, njs_value_t *value, njs_int_t proto_id,
384	    njs_external_ptr_t external, njs_bool_t shared)
385	{
386	    njs_arr_t           **pprotos;
387	    njs_object_value_t  *ov;
388	    njs_exotic_slots_t  *slots;
389	
390	    if (vm->protos == NULL || (njs_int_t) vm->protos->items <= proto_id) {
391	        return NJS_ERROR;
392	    }
393	
394	    ov = njs_object_value_alloc(vm, NJS_OBJ_TYPE_OBJECT, 0, NULL);
395	    if (njs_slow_path(ov == NULL)) {
396	        return NJS_ERROR;
397	    }
398	
399	    pprotos = njs_arr_item(vm->protos, proto_id);
400	    slots = (*pprotos)->start;
401	
402	    ov->object.shared_hash = slots->external_shared_hash;
403	    ov->object.shared = shared;
404	    ov->object.slots = slots;
405	
406	    njs_set_object_value(value, ov);
407	    njs_set_data(&ov->value, external, njs_make_tag(proto_id));
408	
409	    return NJS_OK;
410	}
411	
412	
413	njs_external_ptr_t
414	njs_vm_external(njs_vm_t *vm, njs_int_t proto_id, const njs_value_t *value)
415	{
416	    njs_external_ptr_t  external;
417	
418	    if (njs_fast_path(njs_is_object_data(value, njs_make_tag(proto_id)))) {
419	        external = njs_object_data(value);
420	        if (external == NULL) {
421	            external = vm->external;
422	        }
423	
424	        return external;
425	    }
426	
427	    return NULL;
428	}
429	
430	
431	njs_int_t
432	njs_value_external_tag(const njs_value_t *value)
433	{
434	    if (njs_is_object_data(value, njs_make_tag(NJS_PROTO_ID_ANY))) {
435	        return njs_object_value(value)->data.magic32;
436	    }
437	
438	    return -1;
439	}
440	
441	
442	njs_int_t
443	njs_external_property(njs_vm_t *vm, njs_object_prop_t *prop, uint32_t unused,
444	    njs_value_t *value, njs_value_t *setval, njs_value_t *retval)
445	{
446	    char        *p;
447	    njs_int_t   i;
448	    njs_uint_t  ui;
449	
450	    p = njs_vm_external(vm, NJS_PROTO_ID_ANY, value);
451	    if (p == NULL) {
452	        njs_value_undefined_set(retval);
453	        return NJS_DECLINED;
454	    }
455	
456	    switch (njs_vm_prop_magic16(prop)) {
457	    case NJS_EXTERN_TYPE_INT:
458	        i = *(njs_int_t *) (p + njs_vm_prop_magic32(prop));
459	        njs_value_number_set(retval, i);
460	        break;
461	
462	    case NJS_EXTERN_TYPE_UINT:
463	        ui = *(njs_uint_t *) (p + njs_vm_prop_magic32(prop));
464	        njs_value_number_set(retval, ui);
465	        break;
466	
467	    case NJS_EXTERN_TYPE_VALUE:
468	    default:
469	        njs_value_assign(retval,
470	                         (njs_value_t *) (p + njs_vm_prop_magic32(prop)));
471	
472	    }
473	
474	    return NJS_OK;
475	}
